import com.openai.client.OpenAIClient;
import com.openai.client.okhttp.OpenAIOkHttpClient;
import com.openai.core.JsonValue;
import com.openai.models.chat.completions.ChatCompletion;
import com.openai.models.chat.completions.ChatCompletionCreateParams;

public class Main {
    public static void main(String[] args) {
        try {
            OpenAIClient client = OpenAIOkHttpClient.builder()
                    .apiKey(System.getenv("DASHSCOPE_API_KEY"))
                    .baseUrl("https://[workspace-id].cn-beijing.maas.aliyuncs.com/compatible-mode/v1")
                    .build();

            ChatCompletionCreateParams params = ChatCompletionCreateParams.builder()
                    .model("tongyi-xiaomi-analysis-pro")
                    .addUserMessage(getUserMessage())
                    .temperature(0.0)
                    .putAdditionalBodyProperty("top_k", JsonValue.from(1))
                    .build();

            ChatCompletion chatCompletion = client.chat().completions().create(params);
            String content = chatCompletion.choices().get(0).message().content().orElse("未返回有效内容");
            System.out.println(content);

        } catch (Exception e) {
            System.err.println("Error Message: " + e.getMessage());
        }
    }

    private static String getUserMessage() {
        String analysisPrompt = "请帮我提取下面对话中的关键信息：[1] 客服：您好，欢迎致电AB电商平台，请问有什么可以帮您？[2] 客户：你好，我上周在你们店买了一台料理机，现在运行时有点异响。";

        return analysisPrompt;
    }
}

