import java.util.Arrays;
import java.lang.System;
import com.alibaba.dashscope.aigc.generation.Generation;
import com.alibaba.dashscope.aigc.generation.GenerationParam;
import com.alibaba.dashscope.aigc.generation.GenerationResult;
import com.alibaba.dashscope.common.Message;
import com.alibaba.dashscope.common.Role;
import com.alibaba.dashscope.exception.ApiException;
import com.alibaba.dashscope.exception.InputRequiredException;
import com.alibaba.dashscope.exception.NoApiKeyException;
import com.alibaba.dashscope.protocol.Protocol;

public class Main {
    public static GenerationResult callWithMessage() throws ApiException, NoApiKeyException, InputRequiredException {
        Generation gen = new Generation(Protocol.HTTP.getValue(), "https://[workspace-id].cn-beijing.maas.aliyuncs.com/api/v1");

        Message userMsg = Message.builder()
                .role(Role.USER.getValue())
                .content(getContent())
                .build();

        GenerationParam param = GenerationParam.builder()
                .apiKey(System.getenv("DASHSCOPE_API_KEY"))
                .model("tongyi-xiaomi-analysis-pro")
                .messages(Arrays.asList(userMsg))
                .temperature(0.0f)
                .topK(1)
                .resultFormat(GenerationParam.ResultFormat.MESSAGE)
                .build();
        return gen.call(param);
    }

    public static void main(String[] args) {
        try {
            GenerationResult result = callWithMessage();
            System.out.println(result.getOutput().getChoices().get(0).getMessage().getContent());
        } catch (ApiException | NoApiKeyException | InputRequiredException e) {
            System.err.println("Error message: "+e.getMessage());
        }
    }

    private static String getContent() {

        String analysisPrompt = "请帮我提取下面对话中的关键信息：[1] 客服：您好，欢迎致电AB电商平台，请问有什么可以帮您？[2] 客户：你好，我上周在你们店买了一台料理机，现在运行时有点异响。";

        return analysisPrompt;
    }
}
